def _dremio_to_nested(dremio: Dremio) -> DremioNested:
    """Convert flat Dremio to nested format."""
    attrs = DremioAttributes()
    _populate_dremio_attrs(attrs, dremio)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        dremio, _DREMIO_REL_FIELDS, DremioRelationshipAttributes
    )
    return DremioNested(
        guid=dremio.guid,
        type_name=dremio.type_name,
        status=dremio.status,
        version=dremio.version,
        create_time=dremio.create_time,
        update_time=dremio.update_time,
        created_by=dremio.created_by,
        updated_by=dremio.updated_by,
        classifications=dremio.classifications,
        classification_names=dremio.classification_names,
        meanings=dremio.meanings,
        labels=dremio.labels,
        business_attributes=dremio.business_attributes,
        custom_attributes=dremio.custom_attributes,
        pending_tasks=dremio.pending_tasks,
        proxy=dremio.proxy,
        is_incomplete=dremio.is_incomplete,
        provenance_type=dremio.provenance_type,
        home_id=dremio.home_id,
        depth=dremio.depth,
        immediate_upstream=dremio.immediate_upstream,
        immediate_downstream=dremio.immediate_downstream,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )


def _dremio_from_nested(nested: DremioNested) -> Dremio:
    """Convert nested format to flat Dremio."""
    attrs = nested.attributes if nested.attributes is not UNSET else DremioAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _DREMIO_REL_FIELDS,
        DremioRelationshipAttributes,
    )
    return Dremio(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        depth=nested.depth,
        immediate_upstream=nested.immediate_upstream,
        immediate_downstream=nested.immediate_downstream,
        **_extract_dremio_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )


def _dremio_to_nested_bytes(dremio: Dremio, serde: Serde) -> bytes:
    """Convert flat Dremio to nested JSON bytes."""
    return serde.encode(_dremio_to_nested(dremio))


def _dremio_from_nested_bytes(data: bytes, serde: Serde) -> Dremio:
    """Convert nested JSON bytes to flat Dremio."""
    nested = serde.decode(data, DremioNested)
    return _dremio_from_nested(nested)


